    40	enum class StructureLevel : uint8_t {
    41		NONE = 0, // No tree structure info
    42		MINIMAL,  // + parent_id, depth, sibling_index (O(1) fields)
    43		FULL      // + children_count, descendant_count (O(child_count) fields)
    44	};
    45	
    46	enum class PeekLevel : uint8_t {
