   275				stack.pop_back();
   276			}
   277		}
   278	
   279		// === TREE-SITTER MEMORY PHASE END ===
   280		// Smart pointer automatically cleans up tree-sitter memory here.
   281		// After this point, all TSNode references become INVALID.
   282		// ASTResult must contain only OWNED, RAII-managed data.
   283	
   284		// Set metadata
   285		result.parse_time = start_time;
