 62	ASTResult UnifiedASTBackend::ParseToASTResultTemplated(const AdapterType *adapter, const string &content,
 63	                                                       const string &language, const string &file_path,
 64	                                                       const ExtractionConfig &config) {
 65		ASTResult result;
 66		result.source.file_path = file_path;
 67		result.source.language = language;
 68		auto start_time = std::chrono::system_clock::now();
 69	
 70		// === TREE-SITTER MEMORY PHASE BEGIN ===
 71		// Parse the content using the adapter's smart pointer wrapper
 72		TSTreePtr tree = adapter->ParseContent(content);
 73		if (!tree) {
 74			throw InternalException("Failed to parse content");
 75		}
 76	
 77		// MEMORY SAFETY: All TSNode objects are lightweight references into tree-sitter memory.
 78		// ALL extracted VALUES must be immediately copied when stored in ASTNode fields.
 79		// NO TSNode references should escape this function scope.
 80	
 81		// Process tree into ASTNodes using DFS ordering with O(1) descendant counting
 82		TSNode root = ts_tree_root_node(tree.get());
 83		uint32_t max_depth = 0;
 84	
 85		struct StackEntry {
 86			TSNode node;
 87			int64_t parent_id;
 88			uint32_t depth;
 89			uint32_t sibling_index;
 90			bool processed;   // Track if node has been processed
 91			idx_t node_index; // Index in nodes array for this node
 92		};
 93	
 94		// Hoist GetNodeConfigs outside the hot loop - huge performance optimization!
 95		const auto &node_configs = adapter->GetNodeConfigs();
 96	
 97		vector<StackEntry> stack;
 98		stack.push_back({root, -1, 0, 0, false, 0});
 99	
100		while (!stack.empty()) {
101			// Check if the top entry is processed before copying
102			if (!stack.back().processed) {
103				// Copy the entry to avoid reference invalidation when stack reallocates
104				auto entry = stack.back();
105				// First visit - create node and add children
106				entry.processed = true;
107				entry.node_index = result.nodes.size();
108	
109				// Update the stack entry with the processed flag and node_index
110				stack.back().processed = true;
111				stack.back().node_index = entry.node_index;
112	
113				// Track max depth
114				max_depth = std::max(max_depth, entry.depth);
115	
116				// Create ASTNode
117				ASTNode ast_node;
118	
119				// Basic information - use node_index as node_id
120				ast_node.node_id = entry.node_index;
121	
122				// MEMORY SAFETY: Explicit copy of tree-sitter string data
123				const char *ts_type = ts_node_type(entry.node); // Points to tree-sitter memory
124				ast_node.type_raw = string(ts_type);            // COPY to owned std::string
125	
126				// Position information -> NEW STRUCTURED FIELDS
127				// Only populate source location fields based on config.source level
128				if (config.source >= SourceLevel::PATH) {
129					// File path and language available at PATH level and above
130					ast_node.file_path = file_path;
131					ast_node.language = language;
132				} else {
133					ast_node.file_path = "";
134					ast_node.language = "";
135				}
136	
137				if (config.source >= SourceLevel::LINES_ONLY) {
138					TSPoint start = ts_node_start_point(entry.node);
139					TSPoint end = ts_node_end_point(entry.node);
140					ast_node.source_start_line = start.row + 1;
141					ast_node.source_end_line = end.row + 1;
142	
143					// Column information only available at FULL level
144					if (config.source >= SourceLevel::FULL) {
145						ast_node.source_start_column = start.column + 1;
146						ast_node.source_end_column = end.column + 1;
147					} else {
148						ast_node.source_start_column = 0;
149						ast_node.source_end_column = 0;
150					}
151				} else {
152					// No line/column info
153					ast_node.source_start_line = 0;
154					ast_node.source_end_line = 0;
155					ast_node.source_start_column = 0;
156					ast_node.source_end_column = 0;
157				}
158	
159				// Tree structure -> FLATTENED FIELDS
160				// Only populate structure fields based on config.structure level
161				if (config.structure >= StructureLevel::MINIMAL) {
162					ast_node.parent_id = entry.parent_id;
163					ast_node.depth = entry.depth;
164					ast_node.sibling_index = entry.sibling_index;
165	
166					// Child/descendant counts only available at FULL level
167					if (config.structure >= StructureLevel::FULL) {
168						uint32_t child_count = ts_node_child_count(entry.node);
169						ast_node.children_count = child_count;
170						ast_node.descendant_count = 0; // Will be calculated on second visit
171					} else {
172						ast_node.children_count = 0;
173						ast_node.descendant_count = 0;
174					}
175				} else {
176					// No structure info
177					ast_node.parent_id = -1;
178					ast_node.depth = 0;
179					ast_node.sibling_index = 0;
180					ast_node.children_count = 0;
181					ast_node.descendant_count = 0;
182				}
183	
184				// Store child_count for later use regardless of structure level
185				uint32_t child_count = ts_node_child_count(entry.node);
186	
187				// Context information -> NEW STRUCTURED FIELDS
188				// Only populate context fields based on config.context level
189				if (config.context >= ContextLevel::NORMALIZED) {
190					string raw_name = adapter->ExtractNodeName(entry.node, content);
191					ast_node.name_raw = SanitizeUTF8(raw_name);
192				} else {
193					ast_node.name_raw = "";
194				}
195	
196				// Extract source text (peek) with configurable size and mode
197				uint32_t start_byte = ts_node_start_byte(entry.node); // By-value copy ✅
198				uint32_t end_byte = ts_node_end_byte(entry.node);     // By-value copy ✅
199				if (start_byte < content.size() && end_byte <= content.size() && end_byte > start_byte) {
200					// MEMORY SAFETY: Create owned copy of source text slice
201					string source_text = content.substr(start_byte, end_byte - start_byte); // COPY ✅
202	
203					// Apply peek configuration and sanitize UTF-8
204					if (config.peek == PeekLevel::NONE || config.peek_size == 0) {
205						ast_node.peek = ""; // Empty string will become NULL in output
206					} else if (config.peek == PeekLevel::FULL || config.peek_size == -1) {
207						ast_node.peek = SanitizeUTF8(source_text);
208					} else if (config.peek == PeekLevel::SMART) {
209						// Smart mode: adapt to content size and type
210						if (source_text.length() <= 50) {
211							// Small nodes: full content
212							ast_node.peek = SanitizeUTF8(source_text);
213						} else if (source_text.find('\n') == string::npos) {
214							// Single-line: truncate at display width
215							ast_node.peek =
216							    SanitizeUTF8(source_text.length() > 80 ? source_text.substr(0, 77) + "..." : source_text);
217						} else {
218							// Multi-line: first meaningful line with smart truncation
219							size_t newline_pos = source_text.find('\n');
220							string first_line = source_text.substr(0, newline_pos);
221							ast_node.peek =
222							    SanitizeUTF8(first_line.length() > 80 ? first_line.substr(0, 77) + "..." : first_line);
223						}
224					} else if (config.peek == PeekLevel::CUSTOM) {
225						// Custom size mode
226						uint32_t effective_size = config.peek_size > 0 ? config.peek_size : 120;
227						ast_node.peek = SanitizeUTF8(
228						    source_text.length() > effective_size ? source_text.substr(0, effective_size) : source_text);
229					} else {
230						// Default fallback (shouldn't happen)
231						ast_node.peek = SanitizeUTF8(source_text.length() > 120 ? source_text.substr(0, 120) : source_text);
232					}
233				}
234	
235				// Populate semantic type and other fields - pass configs to avoid virtual call
236				// Only populate semantic fields based on config.context level
237				if (config.context >= ContextLevel::NODE_TYPES_ONLY) {
238					PopulateSemanticFieldsTemplated(ast_node, adapter, entry.node, content, node_configs, config);
239				} else {
240					// No context info - set minimal defaults (use flat fields)
241					ast_node.semantic_type = 0;
242					ast_node.universal_flags = 0;
243					ast_node.arity_bin = 0;
244					ast_node.type_normalized = "";
245					ast_node.native_extraction_attempted = false;
246				}
247	
248				// Update legacy fields for backward compatibility
249				ast_node.UpdateComputedLegacyFields();
250	
251				result.nodes.push_back(ast_node);
252	
253				// Add children to stack in reverse order for correct processing
254				int64_t current_id = ast_node.node_index;
255				for (int32_t i = child_count - 1; i >= 0; i--) {
256					TSNode child = ts_node_child(entry.node, i);
257					stack.push_back({child, current_id, entry.depth + 1, static_cast<uint32_t>(i), false, 0});
258				}
259			} else {
260				// Second visit - get the processed entry for descendant calculation
261				auto entry = stack.back();
262	
263				// O(1) descendant count calculation!
264				// All nodes between entry.node_index+1 and nodes.size() are descendants
265				// due to DFS ordering
266				// Only update if structure level allows it
267				if (config.structure >= StructureLevel::FULL) {
268					int32_t descendant_count = result.nodes.size() - entry.node_index - 1;
269					result.nodes[entry.node_index].descendant_count = descendant_count;
270				}
271	
272				// Update legacy fields after descendant count change
273				result.nodes[entry.node_index].UpdateComputedLegacyFields();
274	
275				stack.pop_back();
276			}
277		}
278	
279		// === TREE-SITTER MEMORY PHASE END ===
280		// Smart pointer automatically cleans up tree-sitter memory here.
281		// After this point, all TSNode references become INVALID.
282		// ASTResult must contain only OWNED, RAII-managed data.
283	
284		// Set metadata
285		result.parse_time = start_time;
286		result.node_count = result.nodes.size();
287		result.max_depth = max_depth;
288	
289		return result;
290	}
