368	// Legacy template version for backward compatibility
369	template <typename AdapterType>
370	ASTResult UnifiedASTBackend::ParseToASTResultTemplated(const AdapterType *adapter, const string &content,
371	                                                       const string &language, const string &file_path,
372	                                                       int32_t peek_size, const string &peek_mode) {
373		// Convert legacy parameters to ExtractionConfig
374		ExtractionConfig config;
375		config.peek_size = peek_size;
376	
377		// Map legacy peek_mode to PeekLevel
378		if (peek_mode == "none") {
379			config.peek = PeekLevel::NONE;
380		} else if (peek_mode == "smart") {
381			config.peek = PeekLevel::SMART;
382		} else if (peek_mode == "full") {
383			config.peek = PeekLevel::FULL;
384		} else if (peek_mode == "compact") {
385			config.peek = PeekLevel::SMART; // Map compact to smart
386		} else {
387			config.peek = PeekLevel::SMART; // Default
388		}
389	
390		// Call the new version
391		return ParseToASTResultTemplated(adapter, content, language, file_path, config);
392	}
